# Safe division — catching ZeroDivisionError
def safe_divide(a, b):
    try:
        result = a / b
        print("Answer:", result)
    except ZeroDivisionError:
        print("Error: Cannot divide by zero!")

safe_divide(10, 2)
safe_divide(9, 3)
safe_divide(5, 0)

